// // This module implements a 32-entry register file with read and write capabilities for 32-bit wide data. It supports two simultaneous read operations using rs1_i and rs2_i, returning the corresponding data from the general-purpose registers. However, if either input register address is non-zero, it returns a constant zero.
module top_module(
    input wire       clk,   
    input wire[4:0]  rs1_i, 
    input wire[4:0]  rs2_i, 
    input wire[4:0]  rd_i,  
    input wire       w_en,  
    input wire[31:0] w_data, 

    output wire[31:0] rs1_o, 
    output wire[31:0] rs2_o  
    );reg[31:0] gpr[31:0]; 

    assign rs1_o = (rs1_i == 0) ? 32'h00000000 : gpr[rs1_i]; 
    assign rs2_o = (rs2_i == 0) ? 32'h00000000 : gpr[rs2_i]; 

    always @ (posedge clk) begin
        if (w_en) begin
            gpr[rd_i] <= w_data; 
        end
    end
endmodule
